import { defineStore } from 'pinia'
import { ref, computed } from 'vue'

export const useWebSocketStore = defineStore('websocket', () => {
  const ws = ref<WebSocket | null>(null)
  const isConnected = ref(false)
  const reconnectAttempts = ref(0)
  const maxReconnectAttempts = 5
  const reconnectDelay = ref(1000)

  const eventHandlers = ref<Map<string, Function[]>>(new Map())

  function connect() {
    const wsUrl = import.meta.env.VITE_WS_BASE_URL || 'ws://localhost:3000/api/ws'

    ws.value = new WebSocket(wsUrl)

    ws.value.onopen = () => {
      console.log('WebSocket connected')
      isConnected.value = true
      reconnectAttempts.value = 0
      reconnectDelay.value = 1000

      // 订阅所有事件
      send({ action: 'subscribe', channel: 'all' })
    }

    ws.value.onmessage = (event) => {
      try {
        const message = JSON.parse(event.data)
        emit(message.event, message.data)
      } catch (error) {
        console.error('Failed to parse WebSocket message:', error)
      }
    }

    ws.value.onclose = () => {
      console.log('WebSocket disconnected')
      isConnected.value = false

      // 自动重连
      if (reconnectAttempts.value < maxReconnectAttempts) {
        setTimeout(() => {
          reconnectAttempts.value++
          reconnectDelay.value = Math.min(reconnectDelay.value * 2, 30000)
          console.log(`Reconnecting... (attempt ${reconnectAttempts.value})`)
          connect()
        }, reconnectDelay.value)
      }
    }

    ws.value.onerror = (error) => {
      console.error('WebSocket error:', error)
    }
  }

  function disconnect() {
    if (ws.value) {
      ws.value.close()
      ws.value = null
    }
    isConnected.value = false
  }

  function send(data: any) {
    if (ws.value && isConnected.value) {
      ws.value.send(JSON.stringify(data))
    }
  }

  function on(event: string, handler: Function) {
    if (!eventHandlers.value.has(event)) {
      eventHandlers.value.set(event, [])
    }
    eventHandlers.value.get(event)?.push(handler)
  }

  function off(event: string, handler: Function) {
    const handlers = eventHandlers.value.get(event)
    if (handlers) {
      const index = handlers.indexOf(handler)
      if (index > -1) {
        handlers.splice(index, 1)
      }
    }
  }

  function emit(event: string, data: any) {
    const handlers = eventHandlers.value.get(event)
    if (handlers) {
      handlers.forEach(handler => handler(data))
    }
  }

  return {
    isConnected,
    reconnectAttempts,
    connect,
    disconnect,
    send,
    on,
    off,
    emit
  }
})
```

