}

onMounted(async () => {
  loading.value = true
  try {
    // 初始化 Agents
    agentStore.initAgents()

    // 加载初始数据
    await refresh()
  } finally {
    loading.value = false
  }

  // 连接 WebSocket
  wsStore.connect()

  // 监听 WebSocket 事件
  wsStore.on('iteration.status_changed', (data: any) => {
    iterationStore.updateIteration(data)
  })

  wsStore.on('agent.status_changed', (data: any) => {
    agentStore.updateAgent(data)
  })

  wsStore.on('iteration.progress', (data: any) => {
    iterationStore.updateProgress(data.progress)
  })

  wsStore.on('system.metrics', (data: any) => {
    systemMetrics.value.push(data)
    // 保持最近100条
    if (systemMetrics.value.length > 100) {
      systemMetrics.value = systemMetrics.value.slice(-100)
    }
  })

  wsStore.on('log.entry', (data: any) => {
    iterationStore.addLog(data)
  })
})

onUnmounted(() => {
  wsStore.disconnect()
})
</script>
